(()=>{var o=document.documentElement,t=null;try{t=localStorage.getItem("pixelforge-theme")}catch{}(t==="light"||t==="dark")&&(o.dataset.theme=t);function c(){let e=o.dataset.theme==="light"?"dark":"light";o.dataset.theme=e;try{localStorage.setItem("pixelforge-theme",e)}catch{}}document.querySelectorAll("[data-theme-toggle]").forEach(e=>{e.addEventListener("click",c)});document.querySelectorAll("[data-year]").forEach(e=>{e.textContent=String(new Date().getFullYear())});var l=document.querySelectorAll(".tool-card,.workflow-grid article,.privacy-card,.cta-card");if("IntersectionObserver"in window){let e=new IntersectionObserver(r=>{r.forEach(a=>{a.isIntersecting&&(a.target.animate([{opacity:0,transform:"translateY(18px)"},{opacity:1,transform:"translateY(0)"}],{duration:520,easing:"cubic-bezier(.2,.7,.2,1)",fill:"both"}),e.unobserve(a.target))})},{threshold:.12});l.forEach(r=>e.observe(r))}})();
